#!/bin/bash
GREEN='\033[0;32m'; BLUE='\033[0;34m'; YELLOW='\033[1;33m'; NC='\033[0m'
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
echo ""
echo -e "${BLUE}╔═══════════════════════════════════════════════╗${NC}"
echo -e "${BLUE}║  Beme — AI Automation Full Install            ║${NC}"
echo -e "${BLUE}╚═══════════════════════════════════════════════╝${NC}"
echo ""
echo -e "${YELLOW}[1/4] DashboardProductDetail — no-question AI prompt + note${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/dashboard/DashboardProductDetail.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/pages/dashboard/DashboardProductDetail.jsx"

echo -e "${YELLOW}[2/4] AIAssistant — auto-reply stats + toggle${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/dashboard/AIAssistant.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/pages/dashboard/AIAssistant.jsx"

echo -e "${YELLOW}[3/4] DashboardChat — copy button + pause AI${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/dashboard/DashboardChat.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/pages/dashboard/DashboardChat.jsx"

echo -e "${YELLOW}[4/4] chatRoutes — smart context B + fallback D + pause check${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Backend/src/routes/chatRoutes.js"
echo -e "  ${GREEN}✓${NC} Beme-Backend/src/routes/chatRoutes.js"

echo -e "${YELLOW}[+] AIMessage — copy button on AI responses${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/components/ai/AIMessage.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/components/ai/AIMessage.jsx"

echo -e "${YELLOW}[+] DashboardChat — copy + pause AI${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/dashboard/DashboardChat.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/pages/dashboard/DashboardChat.jsx"

echo ""
echo -e "${GREEN}╔═══════════════════════════════════════════════╗${NC}"
echo -e "${GREEN}║   ✓  All 4 files installed!                   ║${NC}"
echo -e "${GREEN}╚═══════════════════════════════════════════════╝${NC}"
echo ""
echo -e "${BLUE}Deploy Frontend:${NC}"
echo -e "  cd Beme-Frontend && git add . && git commit -m \"AI automation + chat improvements\" && git push"
echo ""
echo -e "${BLUE}Deploy Backend:${NC}"
echo -e "  cd Beme-Backend && git add . && git commit -m \"Smart context + fallback message\" && git push"
echo ""
echo -e "${YELLOW}One manual step — enable auto-reply in Firestore:${NC}"
echo -e "  Firebase Console → Firestore → aiSettings → {your UID} → customerAutoReplies: true"
echo ""